static long climbStairs(int n) {

    if (n == 0 || n == 1) {
        return 1;
    }

    long prev2 = 1; // ways to reach step 0
    long prev1 = 1; // ways to reach step 1
    long current = 0;

    for (int i = 2; i <= n; i++) {
        current = prev1 + prev2;
        prev2 = prev1;
        prev1 = current;
    }

    return current;
}
